// Build the Gemini prompt for resume tailoring against a job description
const body = $input.first().json.body || $input.first().json || {};

const resumeJson = body.resume_json;
let jdRaw = body.jd_raw || '';

// jd_raw may arrive as string or object — normalise to string
if (typeof jdRaw === 'object') {
  jdRaw = jdRaw.jd_raw || JSON.stringify(jdRaw);
}

if (!resumeJson) {
  throw new Error('resume_json is required in the request body');
}
if (!String(jdRaw).trim()) {
  throw new Error('jd_raw is required in the request body');
}

const resumeStr = JSON.stringify(resumeJson, null, 2);

const outputSchema = JSON.stringify({
  tailored_resume: {
    contact: {
      name: 'string',
      email: 'string',
      phone: 'string',
      linkedin: 'string',
      github: 'string'
    },
    summary: 'string — rewritten to mirror JD language and highlight fit',
    skills: [
      { category: 'string', items: ['string — re-ranked so JD-matching skills appear first'] }
    ],
    experience: [
      {
        company: 'string',
        title: 'string',
        dates: 'string',
        bullets: ['string — rewritten with strong action verbs and JD keywords where truthful']
      }
    ],
    projects: [
      {
        name: 'string',
        tech: ['string'],
        bullets: ['string — rewritten to highlight relevance to JD']
      }
    ],
    education: [
      {
        institution: 'string',
        degree: 'string',
        dates: 'string',
        gpa: 'string'
      }
    ]
  },
  matched_keywords: ['string — keywords/phrases from the JD that appear or are aligned in the tailored resume'],
  ats_score: 'integer 0-100 representing estimated ATS keyword match percentage'
}, null, 2);

const prompt = `You are a professional resume optimization expert specializing in ATS (Applicant Tracking System) optimization.

Your task is to tailor the candidate's resume to the provided job description and return a structured JSON response.

## CRITICAL RULES — READ CAREFULLY:
1. Only use facts from the candidate's input resume. NEVER add skills, companies, job titles, metrics, or technologies not already present in the original resume.
2. You MAY rewrite bullet points to use stronger action verbs and naturally incorporate JD keywords — but only when the underlying fact supports it.
3. You MAY re-rank skills so that skills matching the JD appear first within each category.
4. You MAY rewrite the summary to emphasize the candidate's most relevant experience for this specific role.
5. Do not fabricate GPA, dates, certifications, or any quantitative metrics.
6. The tailored_resume must preserve all original entries (do not drop experience, education, or projects).

## INPUT RESUME (JSON):
${resumeStr}

## JOB DESCRIPTION:
---
${jdRaw}
---

## OUTPUT SCHEMA:
Return a single valid JSON object matching this schema exactly. No markdown fences, no explanation text.

${outputSchema}

## ATS SCORE METHODOLOGY:
- Count distinct keywords/phrases from the JD that are present in the tailored resume.
- Estimate coverage as a percentage (0-100) of the most important JD requirements that are addressed.
- Store that integer in ats_score.

Return the JSON object now:`;

return [{ json: { prompt } }];

// Parse and validate the JSON returned by Gemini for the tailoring response
const response = $input.first().json;

// Navigate the Gemini response envelope
let rawText;
try {
  rawText = response.candidates[0].content.parts[0].text;
} catch (e) {
  throw new Error('Unexpected Gemini response structure: ' + JSON.stringify(response));
}

// Strip any accidental markdown fences
const cleaned = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse Gemini JSON response: ' + e.message + '\nRaw text: ' + rawText);
}

// Validate and normalise the three required top-level keys
if (!parsed.tailored_resume || typeof parsed.tailored_resume !== 'object') {
  throw new Error('Gemini response missing required key: tailored_resume');
}

const tailoredResume = parsed.tailored_resume;

// Ensure all sub-sections exist with safe defaults
const normalised = {
  contact: tailoredResume.contact || { name: '', email: '', phone: '', linkedin: '', github: '' },
  summary: tailoredResume.summary || '',
  skills: Array.isArray(tailoredResume.skills) ? tailoredResume.skills : [],
  experience: Array.isArray(tailoredResume.experience) ? tailoredResume.experience : [],
  projects: Array.isArray(tailoredResume.projects) ? tailoredResume.projects : [],
  education: Array.isArray(tailoredResume.education) ? tailoredResume.education : []
};

const matchedKeywords = Array.isArray(parsed.matched_keywords)
  ? parsed.matched_keywords
  : [];

// Clamp ats_score to integer in [0, 100]
let atsScore = parseInt(parsed.ats_score, 10);
if (isNaN(atsScore)) atsScore = 0;
atsScore = Math.max(0, Math.min(100, atsScore));

return [{
  json: {
    tailored_resume: normalised,
    matched_keywords: matchedKeywords,
    ats_score: atsScore
  }
}];
